export enum AppStatus {
  IDLE = 'IDLE',
  ANALYZING = 'ANALYZING',
  GENERATING_IMAGE = 'GENERATING_IMAGE',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

export interface MarketingPlan {
  headline: string;
  tagline: string;
  cta: string;
  colorTheme: string;
}

export interface GeneratedPoster {
  imageUrl: string;
  optimizedPrompt: string;
}

export interface PosterConfig {
  productImage: string | null; // Base64 for preview
  productImageBase64Raw: string | null; // Raw base64 for API
  productImageType: string;
  promptTemplate: string;
  marketingPlan: MarketingPlan;
}

import { GoogleGenAI, Type } from "@google/genai";

// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Step 1: Analyze the product image and the template to create a specific image generation prompt.
 */
export const optimizePrompt = async (
  imageBase64: string,
  mimeType: string,
  template: string
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: imageBase64,
            },
          },
          {
            text: `You are a world-class creative director.

            Task: Create a highly detailed image generation prompt for a marketing poster.

            Input Product Image: (Attached)
            User's Vibe/Template: "${template}"

            Instructions:
            1. Analyze the attached product image (shape, color, material, core features).
            2. Merge the product details with the User's Template.
            3. Describe the scene, lighting, and composition in vivid detail suitable for an AI image generator.
            4. Ensure the product is the central hero of the image.
            5. Output ONLY the final prompt text. Do not add conversational filler.`
          },
        ],
      },
    });

    return response.text || "A fantastic product poster.";
  } catch (error) {
    console.error("Error optimizing prompt:", error);
    throw new Error("Failed to analyze product and generate prompt.");
  }
};

/**
 * Step 2: Generate the image using the Nano Banana model (Gemini 2.5 Flash Image).
 */
export const generatePosterImage = async (prompt: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image', // Mapped from "nano banana" per requirements
      contents: {
        parts: [
          {
            text: prompt,
          },
        ],
      },
      config: {
        imageConfig: {
           aspectRatio: "3:4", // Poster ratio
        }
      }
    });

    // Iterate to find the image part
    for (const candidate of response.candidates || []) {
        for (const part of candidate.content.parts) {
            if (part.inlineData && part.inlineData.data) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
    }

    throw new Error("No image data found in response.");
  } catch (error) {
    console.error("Error generating image:", error);
    throw new Error("Failed to generate poster image.");
  }
};

